// --- 1. FUNCIÓN PARA OBTENER CONTENIDO DE WIKIS AZURE ---
const getWikiContent = (nodeName) => {
  try {
    // Intenta obtener el primer item del nodo
    const node = $(nodeName).first();
    // Retorna el contenido o string vacío si falla
    return node ? node.json.content : "";
  } catch (error) {
    return "";
  }
};

// --- 2. FUNCIÓN PARA OBTENER Y LIMPIAR RESPUESTA GEMINI ---
const getGeminiContent = (nodeName) => {
  try {
    const node = $(nodeName).first();

    // Validamos que exista la estructura profunda de Gemini
    if (!node || !node.json.candidates || !node.json.candidates[0].content) {
        return "Información no disponible (Estructura Gemini no encontrada)";
    }

    // 1. Extraer el texto crudo
    const rawContent = node.json.candidates[0].content.parts[0].text;

    // 2. Limpiar etiquetas Markdown (Tu lógica de Regex)
    // Esto quita ```json, ```markdown, o ``` simples al inicio y final
    const cleanString = rawContent
      .replace(/^```[a-z]*\s*/i, '') // Quita ```json o ```markdown al inicio
      .replace(/\s*```$/, '');        // Quita ``` al final

    // 3. Retornar texto limpio
    // NOTA: Si esperas un JSON objeto, cambia la línea de abajo por: return JSON.parse(cleanString);
    // Pero para el reporte del video (que es texto), retornamos el string.
    return cleanString.trim();

  } catch (error) {
    return "Error procesando respuesta de Gemini: " + error.message;
  }
};

// --- 3. EJECUCIÓN: OBTENER DATOS DE LOS NODOS ---

// Wikis de Azure
const entrevistas = getWikiContent('1. Cargar Entrevistas');
const personas = getWikiContent('1. Cargar Perfiles Persona');
const storyMap = getWikiContent('1. Cargar Story Mapping');
const journeyMap = getWikiContent('1. Cargar Journey Map');
const pruebaUsuario = getWikiContent('1. Cargar Feedback Prueba Usuario');
const productPlanning = getWikiContent('2. Cargar documento product planning');

// Respuesta de Gemini (Video) usando la nueva función
const analisisPrototipo = getGeminiContent('1. Analista Funcional Video');

// --- 4. RETORNO DEL OBJETO UNIFICADO ---
return [{
  json: {
    fecha_proceso: new Date().toISOString(),

    // Contexto Wiki
    contexto_entrevistas: entrevistas,
    contexto_personas: personas,
    contexto_story_map: storyMap,
    contexto_journey_map: journeyMap,
    contexto_prueba_usuario: pruebaUsuario,
    contexto_product_planning: productPlanning,

    // Contexto Gemini (Limpio)
    contexto_analisis_prototipo: analisisPrototipo
  }
}];

